import dspy

lm = dspy.LM("openai/gpt-4o-mini", api_key="sk-...")
dspy.configure(lm=lm)

# Toy retriever (replace with a real vector store call)
def retrieve(query: str, k: int = 3) -> list[str]:
    corpus = {
        "DSPy": "DSPy is a framework for programming language models.",
        "RAG": "RAG combines retrieval with generation for grounded answers.",
        "MIPRO": "MIPRO optimizes both instructions and few-shot examples jointly.",
    }
    return [v for k2, v in corpus.items() if query.lower() in k2.lower()][:k]

class RAGSignature(dspy.Signature):
    """Answer a question using retrieved context passages."""
    question: str = dspy.InputField()
    context: list[str] = dspy.InputField(desc="Retrieved passages")
    answer: str = dspy.OutputField(desc="Answer grounded in context")

class RAGModule(dspy.Module):
    def __init__(self):
        self.generate = dspy.ChainOfThought(RAGSignature)

    def forward(self, question: str):
        passages = retrieve(question)
        return self.generate(question=question, context=passages)

# Zero-shot usage
rag = RAGModule()
out = rag(question="What is MIPRO?")
print(out.answer)
